from __future__ import annotations

import csv
from pathlib import Path
from typing import Callable, Dict, List, Literal, Optional, Sequence

import numpy as np
import torch
from PIL import Image
from torch.utils.data import Dataset


class UTKFaceBalancedDataset(Dataset):
    """Dataset for balanced UTKFace subsamples generated by setup script.

    Expected directory layout:

    data/utkdataset/
      metadata.csv
      images/
        *.jpg

    The metadata file should include at least: image_path, age, sex
    where sex is 0 (male) or 1 (female).
    """

    def __init__(
        self,
        data_root: str | Path,
        transform: Optional[Callable] = None,
        split: Optional[str] = None,
        target_mode: Literal["age", "sex", "both"] = "both",
    ) -> None:
        self.data_root = Path(data_root)
        self.transform = transform
        self.split = split
        self.target_mode = target_mode

        metadata_path = self.data_root / "metadata.csv"
        if not metadata_path.exists():
            raise FileNotFoundError(
                f"Could not find metadata file at {metadata_path}. "
                "Run scripts/setup/create_utkface_balanced_subsample.py first."
            )

        self.records = self._load_records(metadata_path)
        if len(self.records) == 0:
            raise ValueError(f"No records found in {metadata_path} for split={split!r}")

    def _load_records(self, metadata_path: Path) -> List[Dict[str, str]]:
        records: List[Dict[str, str]] = []

        with metadata_path.open("r", newline="", encoding="utf-8") as csv_file:
            reader = csv.DictReader(csv_file)
            required_fields = {"image_path", "age", "sex"}
            if reader.fieldnames is None or not required_fields.issubset(set(reader.fieldnames)):
                raise ValueError(
                    f"metadata.csv is missing required columns. "
                    f"Found: {reader.fieldnames}, required: {sorted(required_fields)}"
                )

            for row in reader:
                if self.split is not None and row.get("split") != self.split:
                    continue

                image_rel_path = row["image_path"]
                image_path = self.data_root / image_rel_path
                if not image_path.exists():
                    continue

                records.append(row)

        return records

    def __len__(self) -> int:
        return len(self.records)

    def __getitem__(self, index: int):
        row = self.records[index]

        image_path = self.data_root / row["image_path"]
        image = Image.open(image_path).convert("RGB")

        if self.transform is not None:
            image_tensor = self.transform(image)
        else:
            image_tensor = self._to_tensor(image)

        age = torch.tensor(float(row["age"]), dtype=torch.float32)
        sex = torch.tensor(int(row["sex"]), dtype=torch.long)

        if self.target_mode == "age":
            target = age
        elif self.target_mode == "sex":
            target = sex
        else:
            target = {"age": age, "sex": sex}

        return {
            "image": image_tensor,
            "target": target,
            "age": age,
            "sex": sex,
            "image_path": str(image_path),
        }

    @staticmethod
    def _to_tensor(image: Image.Image) -> torch.Tensor:
        tensor = torch.from_numpy(np.array(image)).permute(2, 0, 1)
        return tensor.float() / 255.0


__all__: Sequence[str] = ["UTKFaceBalancedDataset"]
